import{_ as r,c as t,o,ae as s}from"./chunks/framework.Cd-3tpCq.js";const a="/assets/xdebug-phpstorm-01.BA1QQArX.png",n="/assets/xdebug-phpstorm-02.D0hNgZmU.png",u="/assets/xdebug-phpstorm-03.ClpatpdW.png",i="/assets/xdebug-phpstorm-04.Cc4Fl7NS.png",P=JSON.parse('{"title":"Drupal - Configurer XDebug","description":"","frontmatter":{},"headers":[],"relativePath":"00-cheat-sheet/xdebug.md","filePath":"00-cheat-sheet/xdebug.md"}'),l={name:"00-cheat-sheet/xdebug.md"};function p(c,e,d,g,m,b){return o(),t("div",null,e[0]||(e[0]=[s('<h1 id="drupal-configurer-xdebug" tabindex="-1">Drupal - Configurer XDebug <a class="header-anchor" href="#drupal-configurer-xdebug" aria-label="Permalink to &quot;Drupal - Configurer XDebug&quot;">​</a></h1><p><strong>Xdebug</strong> est une extension <strong>PHP</strong> qui permet d’analyser et de déboguer du code en offrant des fonctionnalités comme le pas à pas, l’inspection des variables et le profilage des performances.</p><h2 id="dans-phpstorm" tabindex="-1">Dans PHPStorm <a class="header-anchor" href="#dans-phpstorm" aria-label="Permalink to &quot;Dans PHPStorm&quot;">​</a></h2><p>Créez un serveur dans la configuration de PHPStorm en vous rendant dans <code>Settings-&gt;PHP-&gt;Servers</code>, puis cliquez sur l&#39;icone <code>+</code>.</p><p><img src="'+a+'" alt="XDebug dans PHPStorm - créer un serveur"></p><p>Entrez les informations suivantes :</p><ul><li><strong>Name</strong>: drupal.test</li><li><strong>Host</strong>: drupal.test</li><li><strong>Port</strong>: 80</li><li><strong>Debugger</strong>: Xdebug</li><li><strong>Use path mappings</strong> (cocher la case)</li><li><strong>Absolute path on the server</strong>: ajouter &quot;/app&quot; pour la ligne &quot;Project files&quot;</li></ul><p><img src="'+n+'" alt="XDebug dans PHPStorm - créer un serveur"></p><blockquote><p>⚠️ Le &quot;Host&quot; <code>drupal.test</code> correspond à la valeur précisée dans le fichier <em>compose.yml</em> pour la variable <code>PHP_IDE_CONFIG</code>. Par convention, je garde la même valeur pour le champ &quot;Name&quot;.</p></blockquote><p>Dans la barre du haut, cliquez sur <code>Current File</code>, puis sur <code>Edit Configurations</code>.</p><p><img src="'+u+'" alt="XDebug dans PHPStorm - créer un serveur"></p><p>Cliquez sur <code>+</code> pour ajouter une nouvelle configuration et choisissez <code>PHP web page</code>.</p><p>Remplissez le formulaire avec les informations suivantes :</p><ul><li><strong>Name</strong>: drupal.test</li><li><strong>Server</strong>: drupal.test (le serveur que nous venons de créer)</li><li><strong>HTTPS</strong>: ne cochez pas la case</li><li><strong>Start URL</strong>: /</li><li><strong>Browser</strong>: Sélectionnez votre navigateur préféré ou laissez &quot;default&quot;.</li></ul><p><img src="'+i+'" alt="XDebug dans PHPStorm - créer un serveur"></p><p>Pour activer <strong>XDebug</strong>, il suffit maintenant de cliquer sur l&#39;icone <code>Debug</code> dans la barre du haut. Ce qui va ouvrir le site sur le navigateur.</p>',16)]))}const f=r(l,[["render",p]]);export{P as __pageData,f as default};
